VALUES
  ('social-worker-moex-05710', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '醫務社會工作的個案工作，在評估上主要是以心理暨社會評估取向，經常採用的方式有社會系統紀錄法 （4Rs），下列何者錯誤？', '["Role（社會角色）", "Reaction（情緒反應）", "Recovery（症狀恢復情況）", "Resource（問題解決的資源）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05711', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '案主動機的不足乃是因為案主之內在障礙所致，這些障礙可能導致案主的悲觀、宿命及玩世不恭，若能 給予適度的激勵，給予案主一種對難題解決和成功的意識，即為激勵的重要因素，其主要步驟不包括下 列何者？', '["確定案主的能力和興趣之領域，以界定「可做的」工作", "為解決而演練這些工作", "鼓勵案主指出改變的特定目標", "改變外在環境中之障礙與不穩定因素"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05712', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在兒童及少年社會工作服務中，針對需要保護或替代性服務的兒童及少年，通常是指曾經遭受虐待或不 當對待，因而有照顧需求的兒童或少年，會評估以替代性服務來作為介入之方法。下列何者不屬於替代 性服務的一種？', '["收養", "托養", "寄養", "機構安置"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05713', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在個案管理工作中，資源的確認與集結包括對於機構特性的確認，其中也包括一些潛在的問題，下列何 者錯誤？', '["特殊需求個案所需要的協助呈現超出目前可用的資源", "機構提供不充分或誤導的訊息", "機構宗旨與使命經常改變", "機構提供的資源訊息不能適時更新"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05714', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作在老人整合性評估中，需要認識心理與認知功能之評估工具，下列何者評估工具不屬於心理與 認知功能評估？', '["簡版認知量表（simple portable mental status questionnaire, SPMSQ）", "臨床失智評分表（clinical dementia rating, CDR）", "工具性日常生活功能量表（instrumental activities of daily living, IADL）", "老人憂鬱量表/簡式（geriatric depression scale, GDS）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05715', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作專業必須關心業務過失的發生，並在範圍內保障服務品質及專業信用。下列何者不是預防途徑 之一？', '["社會工作機構必須增加品質保證及風險管理", "社會工作人員必須加強與媒體溝通與互動之能力", "社會工作人員必須增加法學素養、充實法律責任與業務過失的知識", "增加機構督導制度之監督與控管功能"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05716', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作專業倫理所探究之規範倫理學（normative ethics），主旨在探究或反省倫理有效性之基礎或理由。 有關規範倫理學之敘述，下列何者錯誤？', '["規範性倫理理論主要分為義務論和目的論", "義務論認為規則、權利和原則是神聖的和不可違反的", "效益主義屬於義務論的派別之一", "目的論認為任何行動是否具有正當性，決定在後果為善的程度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05717', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關Papell & Rothman（1966）所提出的三種團體工作模型，依其發展先後為社會目標模型、治療模型、 交互模型，下列有關此三種模型的敘述，何者錯誤？', '["社會目標模型的中心概念是社會意識與社會責任", "治療模型對成員的看法是認為案主是接受社會化與消費性服務", "交互模型中工作者的角色是扮演變遷媒介", "社會目標模型與治療模型屬於目標模型，交互模型屬於過程模型"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05718', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作實務往往依賴團體去提供人們每日生活的服務和協助，這些團體傾向正式的並因特定性的目的 而設立。其中具有心理干預目的處理內在本質重點的團體，稱為治療性團體。下列何者不屬於治療性團 體的一種？', '["支持性團體", "社會化團體", "諮商團體", "心理治療團體"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 20, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05719', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '1917年，社會工作專業的鼻祖Mary Richmond出版《社會診斷》（Social Diagnosis）強調社會因素對人 類行為的重要性，主要論述不包括下列那一項？', '["重視與案主一起做（do with）而非傳統調查性和救濟性的為他們做（do for）", "講求科學化、系統步驟蒐集資料，以有組織方式來瞭解問題，並找出問題核心", "當人們正向的能力若可以得到支持，則他們將會以自身的能力去採取行動", "重視個人、家庭與社會之間的互動關係"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
